1	package dnsresolve
2	
3	import (
4		"bytes"
5		"context"
6		"crypto/tls"
7		"crypto/x509"
8		"errors"
9		"fmt"
10		"io"
11		"net"
12		"net/http"
13		"net/netip"
14		"net/url"
15		"strings"
16		"time"
17	
18		"golang.org/x/net/dns/dnsmessage"
19	)
20	
21	// dohMediaType is the RFC 8484 wire-format media type for both the request
22	// body and the expected response body.
23	const dohMediaType = "application/dns-message"
24	
25	// dohTimeout bounds a single DoH POST round trip (request send + response
26	// read). It applies via http.Client.Timeout in addition to whatever deadline
27	// the caller's context already carries.
28	const dohTimeout = 5 * time.Second
29	
30	// dohMaxMessageSize is the maximum wire size of a DNS message (RFC 1035
31	// SS4.2.2 / RFC 8484): the response body is capped to this to bound memory
32	// use against a malicious or misbehaving DoH server, regardless of any
33	// Content-Length header it claims.
34	const dohMaxMessageSize = 65535
35	
36	// DoHResolver resolves hostnames via DNS-over-HTTPS (RFC 8484): it encodes A
37	// and AAAA queries with golang.org/x/net/dns/dnsmessage, POSTs each to a
38	// configured DoH URL, and extracts the answer addrs and minimum TTL.
39	//
40	// Residual leak: the DoH provider (and any network observer) sees the TLS
41	// SNI of the DoH URL's host and the timing/size of each request — DoH hides
42	// the query *content* from on-path observers, not the fact that this host is
43	// talking to that DoH provider.
44	type DoHResolver struct {
45		url    string
46		client *http.Client
47	}
48	
49	var _ Resolver = (*DoHResolver)(nil)
50	
51	// NewDoHResolver returns a Resolver that POSTs DNS-over-HTTPS queries to
52	// rawURL (which must be an https:// URL). Certificate trust uses the
53	// platform's standard root CA store — there is no production knob to disable
54	// certificate verification.
55	func NewDoHResolver(rawURL string) (*DoHResolver, error) {
56		return newDoHResolver(rawURL, nil)
57	}
58	
59	// newDoHResolver is the unexported constructor seam: a non-nil roots pool
60	// overrides the platform trust store with roots, for injecting a test CA
61	// (e.g. from httptest.NewTLSServer) — it exists ONLY for tests in this
62	// package. Production code always goes through NewDoHResolver, which passes
63	// roots=nil and gets tls.Config's default (the system pool).
64	func newDoHResolver(rawURL string, roots *x509.CertPool) (*DoHResolver, error) {
65		parsed, err := url.Parse(rawURL)
66		if err != nil {
67			return nil, fmt.Errorf("dnsresolve: invalid DoH URL %q: %w", rawURL, err)
68		}
69		if parsed.Scheme != "https" {
70			return nil, fmt.Errorf("dnsresolve: DoH URL %q must use https, got scheme %q", rawURL, parsed.Scheme)
71		}
72	
73		transport := &http.Transport{
74			// No proxy surprise: never route DoH queries through an
75			// environment-configured (HTTP_PROXY/HTTPS_PROXY) proxy — a DoH
76			// resolver silently redirected through an unexpected intermediary
77			// would defeat the point of choosing a specific trusted provider.
78			Proxy: nil,
79			TLSClientConfig: &tls.Config{
80				RootCAs:    roots,
81				MinVersion: tls.VersionTLS12,
82			},
83			// HTTP/2 ok: Go only auto-negotiates h2 over a custom
84			// TLSClientConfig when this is set explicitly.
85			ForceAttemptHTTP2: true,
86		}
87	
88		return &DoHResolver{
89			url: rawURL,
90			client: &http.Client{
91				Transport: transport,
92				Timeout:   dohTimeout,
93			},
94		}, nil
95	}
96	
97	// Lookup implements Resolver. It queries A and AAAA for host and merges the
98	// results; a family that answers NXDOMAIN is tolerated as long as the other
99	// family answers. Any other per-family error (transport failure, non-200,
100	// malformed response) fails the whole lookup. An empty final addr set — both
101	// families NXDOMAIN, or a NOERROR/zero-answer (NODATA) response for both —
102	// is also an error (NXDomainError or NoDataError respectively), never a
103	// silent ([], nil).
104	func (d *DoHResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
105		var (
106			addrs    []netip.Addr
107			minTTL   time.Duration
108			haveTTL  bool
109			nxdomain error
110		)
111	
112		for _, qtype := range [...]dnsmessage.Type{dnsmessage.TypeA, dnsmessage.TypeAAAA} {
113			famAddrs, famMinTTL, famHaveTTL, err := d.queryFamily(ctx, host, qtype)
114			if err != nil {
115				var nx *NXDomainError
116				if errors.As(err, &nx) {
117					nxdomain = err
118					continue
119				}
120				return nil, 0, false, err
121			}
122	
123			addrs = append(addrs, famAddrs...)
124			if famHaveTTL && (!haveTTL || famMinTTL < minTTL) {
125				minTTL = famMinTTL
126				haveTTL = true
127			}
128		}
129	
130		// An empty FINAL addr set is a failure, not a success: it covers both a
131		// double-NXDOMAIN (below) and a NOERROR/zero-answer response (NODATA, or
132		// a CNAME with no A/AAAA target) from one or both families. Returning
133		// (nil, nil) here would diverge from SystemResolver, which surfaces a
134		// no-such-host error from net.Resolver.LookupNetIP in the same
135		// situation — callers must not see the two Resolver implementations
136		// behave differently behind the same seam.
137		if len(addrs) == 0 {
138			if nxdomain != nil {
139				return nil, 0, false, nxdomain
140			}
141			return nil, 0, false, &NoDataError{URL: d.url, Host: host}
142		}
143	
144		return addrs, minTTL, haveTTL, nil
145	}
146	
147	// queryFamily runs a single A or AAAA query over DoH.
148	func (d *DoHResolver) queryFamily(ctx context.Context, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
149		query, err := buildDoHQuery(host, qtype)
150		if err != nil {
151			return nil, 0, false, fmt.Errorf("dnsresolve: encoding DoH query for %q: %w", host, err)
152		}
153	
154		req, err := http.NewRequestWithContext(ctx, http.MethodPost, d.url, bytes.NewReader(query))
155		if err != nil {
156			return nil, 0, false, fmt.Errorf("dnsresolve: building DoH request to %s: %w", d.url, err)
157		}
158		req.Header.Set("Content-Type", dohMediaType)
159		req.Header.Set("Accept", dohMediaType)
160	
161		resp, err := d.client.Do(req)
162		if err != nil {
163			if isTimeoutErr(err) {
164				return nil, 0, false, &TimeoutError{URL: d.url, Err: err}
165			}
166			return nil, 0, false, fmt.Errorf("dnsresolve: DoH POST to %s failed: %w", d.url, err)
167		}
168		defer resp.Body.Close()
169	
170		if resp.StatusCode != http.StatusOK {
171			return nil, 0, false, &StatusError{URL: d.url, StatusCode: resp.StatusCode}
172		}
173	
174		// Cap the read at dohMaxMessageSize+1: a DNS message can never legally
175		// exceed dohMaxMessageSize bytes, so reading one extra byte lets us
176		// detect and reject an oversized body without trusting an
177		// attacker-controlled Content-Length or buffering an unbounded stream.
178		body, err := io.ReadAll(io.LimitReader(resp.Body, dohMaxMessageSize+1))
179		if err != nil {
180			if isTimeoutErr(err) {
181				return nil, 0, false, &TimeoutError{URL: d.url, Err: err}
182			}
183			return nil, 0, false, &MalformedResponseError{URL: d.url, Err: err}
184		}
185		if len(body) > dohMaxMessageSize {
186			return nil, 0, false, &MalformedResponseError{
187				URL: d.url,
188				Err: fmt.Errorf("response body exceeds max DNS message size of %d bytes", dohMaxMessageSize),
189			}
190		}
191	
192		return parseDoHResponse(d.url, body, host, qtype)
193	}
194	
195	// buildDoHQuery packs a single-question A/AAAA query. Per RFC 8484 SS4.1, it
196	// uses a DNS ID of 0 to maximize HTTP cache friendliness.
197	func buildDoHQuery(host string, qtype dnsmessage.Type) ([]byte, error) {
198		name, err := dnsmessage.NewName(fqdn(host))
199		if err != nil {
200			return nil, err
201		}
202		msg := dnsmessage.Message{
203			Header: dnsmessage.Header{
204				ID:               0,
205				RecursionDesired: true,
206			},
207			Questions: []dnsmessage.Question{
208				{Name: name, Type: qtype, Class: dnsmessage.ClassINET},
209			},
210		}
211		return msg.Pack()
212	}
213	
214	// parseDoHResponse unpacks body and extracts the addrs and minimum TTL of
215	// the qtype records it contains.
216	func parseDoHResponse(dohURL string, body []byte, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
217		var msg dnsmessage.Message
218		if err := msg.Unpack(body); err != nil {
219			return nil, 0, false, &MalformedResponseError{URL: dohURL, Err: err}
220		}
221	
222		if msg.RCode == dnsmessage.RCodeNameError {
223			return nil, 0, false, &NXDomainError{URL: dohURL, Host: host}
224		}
225		if msg.RCode != dnsmessage.RCodeSuccess {
226			return nil, 0, false, &MalformedResponseError{URL: dohURL, Err: fmt.Errorf("response RCode %v", msg.RCode)}
227		}
228	
229		var addrs []netip.Addr
230		var minTTL time.Duration
231		haveTTL := false
232		for _, ans := range msg.Answers {
233			if ans.Header.Class != dnsmessage.ClassINET {
234				continue
235			}
236	
237			var addr netip.Addr
238			switch res := ans.Body.(type) {
239			case *dnsmessage.AResource:
240				if qtype != dnsmessage.TypeA {
241					continue
242				}
243				addr = netip.AddrFrom4(res.A)
244			case *dnsmessage.AAAAResource:
245				if qtype != dnsmessage.TypeAAAA {
246					continue
247				}
248				addr = netip.AddrFrom16(res.AAAA)
249			default:
250				continue
251			}
252	
253			addrs = append(addrs, addr)
254			ttl := time.Duration(ans.Header.TTL) * time.Second
255			if !haveTTL || ttl < minTTL {
256				minTTL = ttl
257				haveTTL = true
258			}
259		}
260	
261		return addrs, minTTL, haveTTL, nil
262	}
263	
264	// fqdn returns host with a trailing dot, as dnsmessage.Name requires.
265	func fqdn(host string) string {
266		if strings.HasSuffix(host, ".") {
267			return host
268		}
269		return host + "."
270	}
271	
272	// isTimeoutErr reports whether err represents a request that exceeded its
273	// deadline (context deadline or http.Client/net.Dialer timeout).
274	func isTimeoutErr(err error) bool {
275		var netErr net.Error
276		if errors.As(err, &netErr) && netErr.Timeout() {
277			return true
278		}
279		return errors.Is(err, context.DeadlineExceeded)
280	}
281	
282	// StatusError reports a DoH provider responding with a non-200 HTTP status.
283	type StatusError struct {
284		URL        string
285		StatusCode int
286	}
287	
288	func (e *StatusError) Error() string {
289		return fmt.Sprintf("dnsresolve: DoH %s returned HTTP status %d", e.URL, e.StatusCode)
290	}
291	
292	// MalformedResponseError reports a DoH response body that failed to decode
293	// as a valid DNS message, or that decoded to an unexpected RCode.
294	type MalformedResponseError struct {
295		URL string
296		Err error
297	}
298	
299	func (e *MalformedResponseError) Error() string {
300		return fmt.Sprintf("dnsresolve: DoH %s returned a malformed response: %v", e.URL, e.Err)
301	}
302	
303	func (e *MalformedResponseError) Unwrap() error { return e.Err }
304	
305	// TimeoutError reports a DoH request that did not complete within its
306	// deadline.
307	type TimeoutError struct {
308		URL string
309		Err error
310	}
311	
312	func (e *TimeoutError) Error() string {
313		return fmt.Sprintf("dnsresolve: DoH %s request timed out: %v", e.URL, e.Err)
314	}
315	
316	func (e *TimeoutError) Unwrap() error { return e.Err }
317	
318	// NXDomainError reports a DoH provider answering NXDOMAIN for one address
319	// family. Lookup tolerates this as long as the other family answers.
320	type NXDomainError struct {
321		URL  string
322		Host string
323	}
324	
325	func (e *NXDomainError) Error() string {
326		return fmt.Sprintf("dnsresolve: DoH %s: no such host %q", e.URL, e.Host)
327	}
328	
329	// NoDataError reports a DoH provider answering NOERROR with an empty final
330	// A+AAAA addr set for host (NODATA, or a CNAME chain with no A/AAAA
331	// target). It is the DoH-transport counterpart of the no-such-host error
332	// net.Resolver.LookupNetIP returns in the same situation.
333	type NoDataError struct {
334		URL  string
335		Host string
336	}
337	
338	func (e *NoDataError) Error() string {
339		return fmt.Sprintf("dnsresolve: DoH %s: no A/AAAA records for %q", e.URL, e.Host)
340	}
