package dnsresolve

import (
	"context"
	"net/netip"
	"time"
)

// Resolver resolves a hostname to its full A+AAAA record set, context-bounded.
// Implementations return addrs deterministically (both v4 and v6 when present);
// callers filter/order by local path family as needed.
//
// minTTL is the minimum TTL across the returned records when the transport
// exposes it; ttlOk reports whether minTTL is meaningful — it is false when the
// transport discards TTL information (e.g. Go's standard net.Resolver never
// exposes it).
type Resolver interface {
	Lookup(ctx context.Context, host string) (addrs []netip.Addr, minTTL time.Duration, ttlOk bool, err error)
}

// Package dnsresolve defines the DNS resolution seam: a small, context-bounded
// Resolver interface plus two production implementations — SystemResolver
// (the Go standard resolver, over net.Resolver) and DoHResolver (DNS-over-
// HTTPS, RFC 8484). It is the injection point every runtime and test consumer
// resolves hostnames through — a future DoT transport drops in behind the
// same interface, and unit tests across the codebase inject the in-memory
// FakeResolver instead of touching the network.
//
// The package is deliberately free of any device/bind dependency so it stays
// import-cycle-safe from internal/config, internal/device, and tests.
package dnsresolve

package dnsresolve

import (
	"context"
	"net"
	"net/netip"
	"time"
)

// SystemResolver resolves hostnames via the Go standard resolver (net.Resolver),
// requesting both A and AAAA records in one call (net.LookupNetIP-shape). The
// standard resolver does not expose record TTLs, so Lookup always returns
// ttlOk=false.
type SystemResolver struct {
	resolver *net.Resolver
}

var _ Resolver = (*SystemResolver)(nil)

// NewSystemResolver returns a Resolver backed by net.DefaultResolver.
func NewSystemResolver() *SystemResolver {
	return &SystemResolver{resolver: net.DefaultResolver}
}

// Lookup implements Resolver.
func (s *SystemResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
	addrs, err := s.resolver.LookupNetIP(ctx, "ip", host)
	if err != nil {
		return nil, 0, false, err
	}
	return addrs, 0, false, nil
}

